package privateuser

import (
	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/users/dto"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

func GetPrivateProfileHandler(svc dusers.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		user, httperr := authsvc.ValidateUserAndEnforcePasswordChangeGetUser(r, svc)
		if httperr != nil {
			_ = handlers.WriteFailure(w, httperr.StatusCode, authFailureReason(httperr))
			return
		}

		profile, err := svc.GetPrivateProfile(r.Context(), user.Username)
		if err != nil {
			if err == dusers.ErrUserNotFound {
				_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonUserNotFound)
				return
			}
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		_ = handlers.WriteResult(w, http.StatusOK, privateProfileResponse(profile))
	}
}

func authFailureReason(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}
	switch err.StatusCode {
	case http.StatusUnauthorized:
		return handlers.ReasonInvalidToken
	case http.StatusForbidden:
		return handlers.ReasonPasswordChangeRequired
	case http.StatusNotFound:
		return handlers.ReasonUserNotFound
	default:
		return handlers.ReasonInternalError
	}
}

func privateProfileResponse(profile *dusers.PrivateProfile) dto.PrivateUserResponse {
	if profile == nil {
		return dto.PrivateUserResponse{}
	}

	return dto.PrivateUserResponse{
		ID:                    profile.ID,
		Username:              profile.Username,
		DisplayName:           profile.DisplayName,
		UserType:              profile.UserType,
		InitialAccountBalance: profile.InitialAccountBalance,
		AccountBalance:        profile.AccountBalance,
		PersonalEmoji:         profile.PersonalEmoji,
		Description:           profile.Description,
		PersonalLink1:         profile.PersonalLink1,
		PersonalLink2:         profile.PersonalLink2,
		PersonalLink3:         profile.PersonalLink3,
		PersonalLink4:         profile.PersonalLink4,
		Email:                 profile.Email,
		APIKey:                profile.APIKey,
		MustChangePassword:    profile.MustChangePassword,
	}
}

package auth

import (
	"errors"
	"net/http"
	"strings"

	"github.com/golang-jwt/jwt/v4"
)

type HTTPError struct {
	StatusCode int
	Message    string
}

func (e *HTTPError) Error() string {
	return e.Message
}

// ExtractTokenFromHeader extracts the JWT token from the Authorization header of the request
func extractTokenFromHeader(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return "", errors.New("authorization header is required")
	}
	return strings.TrimPrefix(authHeader, "Bearer "), nil
}

// ParseToken parses the JWT token and returns the claims
func parseToken(tokenString string, keyFunc jwt.Keyfunc) (*jwt.Token, error) {
	return jwt.ParseWithClaims(tokenString, &UserClaims{}, keyFunc)
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"

	"github.com/golang-jwt/jwt/v4"
)

func Authenticate(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Here you would verify the JWT token or session
		// If it's valid, call next.ServeHTTP to pass to the next handler
		// Otherwise, return an error
	})
}

// ValidateUserAndEnforcePasswordChange performs user validation and checks if a password change is required.
// It returns the user and any errors encountered.
func ValidateUserAndEnforcePasswordChangeGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *HTTPError) {
	user, httpErr := ValidateTokenAndGetUser(r, svc)
	if httpErr != nil {
		return nil, httpErr
	}

	// Check if a password change is required
	if httpErr := CheckMustChangePasswordFlag(user); httpErr != nil {
		return nil, httpErr
	}

	return user, nil
}

// ValidateTokenAndGetUser checks that the user is who they claim to be, and returns their information for use
func ValidateTokenAndGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *HTTPError) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Authorization header is required"}
	}

	tokenString := strings.TrimPrefix(authHeader, "Bearer ")
	token, err := jwt.ParseWithClaims(tokenString, &UserClaims{}, func(token *jwt.Token) (interface{}, error) {
		return getJWTKey(), nil
	})
	if err != nil {
		return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Invalid token"}
	}

	if claims, ok := token.Claims.(*UserClaims); ok && token.Valid {
		user, err := svc.GetUser(r.Context(), claims.Username)
		if err != nil {
			if err == dusers.ErrUserNotFound {
				return nil, &HTTPError{StatusCode: http.StatusNotFound, Message: "User not found"}
			}
			return nil, &HTTPError{StatusCode: http.StatusInternalServerError, Message: "Failed to load user"}
		}
		return user, nil
	}
	return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Invalid token"}
}

// CheckMustChangePasswordFlag checks if the user needs to change their password
func CheckMustChangePasswordFlag(user *dusers.User) *HTTPError {
	if user.MustChangePassword {
		return &HTTPError{
			StatusCode: http.StatusForbidden,
			Message:    "Password change required",
		}
	}
	return nil
}

package auth

import (
	"errors"
	"net/http"
)

// ValidateAdminToken uses the provided authenticator to ensure the request is
// made by an admin user. Prefer calling auth.RequireAdmin directly; this helper
// exists for backwards compatibility with legacy call sites.
func ValidateAdminToken(r *http.Request, auth Authenticator) error {
	if auth == nil {
		return errors.New("authenticator is required")
	}

	user, httpErr := auth.RequireAdmin(r)
	if httpErr != nil {
		return errors.New(httpErr.Message)
	}

	// Extra guard: RequireAdmin already checks admin, but ensure status handling.
	if user == nil {
		return errors.New("unauthorized")
	}

	return nil
}

